const query = $input.first().json.query || {};
const tokenCode = query.token_code;
const status = query.status;
const limit = parseInt(query.limit) || 50;
const offset = parseInt(query.offset) || 0;

return { tokenCode, status, limit, offset };

const params = $input.first().json;
let whereClause = '1=1';
let orderBy = 'ORDER BY created_at DESC';

if (params.tokenCode) {
  whereClause += ` AND token_code = '${params.tokenCode}'`;
}

if (params.status) {
  whereClause += ` AND status = '${params.status}'`;
}

const query = `SELECT id, token_code, from_address, to_address, weight, status, quote_amount, tracking_number, tracking_status, carrier, service_name, estimated_days, label_url, tracking_url, created_at, updated_at FROM demo_shipments WHERE ${whereClause} ${orderBy} LIMIT ${params.limit} OFFSET ${params.offset};`;

return { query };
